record_types.code:
type Entity_Type (Kind : Entity_Kind) is record
   case Kind is
      when file =>
         Line : Natural;
      when variable =>
         Name : Unbounded_String;
         Loops : Natural := 0;
   end case;
end record;

subprograms.code:
function Replace (
   Text        : String;
   Entity      : Entity_Type;
   Success     : out Boolean;
   Output      : IO.File_Access := null
) return String
